(window.courseContentFiles = window.courseContentFiles || {})["000004/0003"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>document</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body {\n      font-family: \"Open Sans\", Arial, sans-serif;\n      max-width: 1550px;\n      margin: 0.5rem auto;\n      padding: 0 1rem;\n      line-height: 1.6;\n      color: #1f2937;\n    }\n    h1, h2, h3, h4 {\n      font-weight: 600;\n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0.1em; }\n    p {\n      margin: 0.3em 0;\n      white-space: pre-wrap;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol {\n      margin-top: 0;\n    }\n    ul, ol {\n      margin: 0.2em 0;\n      padding-left: 1.5em;\n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code {\n      background: rgba(218, 215, 205, 0.3);\n      padding: 2px 6px;\n      border-radius: 3px;\n      font-family: \"Courier New\", monospace;\n      font-size: 0.9em;\n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table {\n      border-collapse: collapse;\n      margin: 0.75em 0;\n      width: 100%;\n      table-layout: auto;\n    }\n    th, td {\n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px;\n      text-align: left;\n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th {\n      background: rgba(88, 129, 87, 0.13);\n      font-weight: 600;\n    }\n    tbody tr:nth-child(odd) {\n      background: rgba(88, 129, 87, 0.06);\n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 7px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n      padding: 5px 7px;\n      border: 1px solid #d8e5d4;\n      border-radius: 9px;\n      background: #f4f9f2;\n    }\n    .audio-link-icon {\n      width: 26px;\n      height: 26px;\n      border: 1px solid #588157;\n      border-radius: 8px !important;\n      background: transparent;\n      color: #2f5d50;\n      cursor: pointer;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 26px;\n      padding: 0;\n      text-align: center;\n      font-size: 12px;\n      font-weight: 700;\n    }\n    .audio-link-icon img,\n    .audio-time {\n      display: none !important;\n    }\n    .audio-link-label {\n      max-width: 125px;\n      min-width: 0;\n      font-size: 0.82em;\n      font-weight: 700;\n      overflow: hidden;\n      text-overflow: ellipsis;\n      white-space: nowrap;\n    }\n    .audio-link-label:empty {\n      display: none;\n    }\n    .audio-progress {\n      width: 118px;\n      accent-color: #588157;\n      cursor: pointer;\n    }\n    .audio-volume {\n      width: 44px;\n      accent-color: #588157;\n      cursor: pointer;\n    }\n    .audio-progress,\n    .audio-volume {\n      height: 4px;\n      appearance: none;\n      -webkit-appearance: none;\n      background: transparent;\n    }\n    .audio-link-inline audio {\n      display: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 900px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n\n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n\n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n\n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n\n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n\n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n\n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n\n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n\n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n\n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n\n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n\n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<blockquote style=\"text-align: left\">Непроверени, взети от съкратени теми</blockquote><h1 style=\"text-align: center\">Тема 45. Цервикобрахиални радикулити и радикулопатии. Плексит.</h1><p>Раменният плексус се образува от <strong>C5–Th1 коренчета</strong>. Тъй като коренчетата и плексусът са тясно свързани, често се засягат едновременно, поради което в някои случаи се използва терминът <strong>радикулоплексит</strong>.</p><h2>Причини</h2><p>Причините могат да бъдат <strong>възпалителни</strong>, <strong>токсо-алергични</strong>, <strong>травматични </strong>и други процеси. Цервикобрахиалните нерви могат да се увредят локално от <strong>дегенеративни процеси в цервикалните прешлени</strong>, <strong>локална остеофитоза</strong>, транспортни травми с луксации и фрактури на прешлените. <strong>Най-честата причина е латерална цервикална дискова херния</strong>.</p><h2>Клинична картина</h2><p>1) <strong>Спонтанна болка</strong> — най-характерният симптом. Има невралгичен характер и понякога се съчетава с автономни вазомоторни явления: изпотяване, зачервяване, оток на ръката и др. Болката е локализирана супра- и инфраклавикуларно и ирадиира по хода на нервите. Палпаторно се установяват <strong><span class=\"editor-note\" data-note=\"**Болкови точки на Вале** са определени места по хода на периферните нерви, които са болезнени при палпация.\nПри **цервикобрахиални радикулити/плексити** те се установяват най-често в **супраклавикуларната и инфраклавикуларната област**, където преминават структури на брахиалния плексус. Болезнеността им насочва към дразнене или увреда на нервните коренчета/плексуса.\" id=\"note-1778573864163-1\">болкови точки на Вале</span></strong>. Има намалена подвижност на шията и горния раменен пояс с принудителна щадяща поза.</p><p>2) <strong>Отпадна сетивна симптоматика</strong> — при засягане на коренчета се проявява с <strong>хипестезия</strong> в съответния дерматом. При засягане на целия брахиален плексус се наблюдава <strong>хипестезия до анестезия</strong> за цялата ръка.</p><p>3) <strong>Периферни вяли парези</strong> — при тежки увреди на плексуса вследствие на травми, серуми, ваксини и др. Освен слабост може да се наблюдава бързо развитие на <strong>мускулни атрофии с болки</strong>.</p><p>4) <strong>Рефлексни нарушения</strong> — сухожилните и надкостни рефлекси на ръката са отслабени до липсващи, в зависимост от засегнатото коренче.</p><p>При плекситите се установяват два основни типа парализи:</p><ul><li><strong>Горен тип плексит</strong> — засяга проксималната група мускули на ръката: <strong>m. deltoideus</strong>, <strong>m. triceps brachii</strong>, <strong>m. biceps brachii</strong>, <strong>m. pectoralis major</strong> и др. Ръката е увиснала надолу, във вътрешна ротация. Рамото не може да се повдигне и стои увиснало. Има слабост на предмишницата.</li><li><strong>Долен тип плексит</strong> — засяга дисталната група мускули: <strong>m. flexor pollicis longus</strong>, <strong>m. flexor carpi radialis</strong>, <strong>m. palmaris longus</strong>, <strong>m. flexor digitorum superficialis et profundus ulnaris</strong>, <strong>m. extensor digitorum</strong>, <strong>mm. interossei</strong> и др. Налице е слабост на пръстите, флексията и екстензията на китката. Атрофията на интеросейните мускули деформира ръката като <strong>„ръка на граблива птица“</strong>.</li><li><strong>Засягането на целия раменен плексус</strong> води до <strong>вяла, атрофична парализа на цялата ръка</strong>. Най-честата причина е травма или възпалителен процес.</li></ul><h2>Диагноза</h2><p>Диагнозата е предимно <strong>клинична</strong>. Търсят се локални промени на шийните прешлени чрез <strong>рентгенография, КТ и МРТ</strong> — дискови хернии, спондилоартрозни промени, цервикално шийно ребро, неопластичен процес и др.</p><h2>Лечение</h2><p>Лечението включва <strong>нестероидни противовъзпалителни средства</strong>, <strong>витамини от група B</strong>, а при вяли парализи и амиотрофии — <strong>Galantamin / Nivalin</strong>. Прилагат се още <strong>физиотерапия, масажи и балнеолечение</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 46. Лумбосакрални радикулити и радикулопатии. Ишиас.</h1><p>Лумбосакралният радикулит най-често представлява <strong>хронично-рецидивиращо заболяване</strong>. Обозначава се и с термините <strong>лумбаго</strong>, <strong>ишиас</strong>, <strong>лумбосакрална радикулопатия</strong>, <strong>low back pain</strong>. При ишиас болката ирадиира по хода на <strong>седалищния нерв</strong>.</p><h2>Етиология</h2><p>Етиологията е свързана с <strong>дегенеративни промени в интервертебралните дискове</strong> при хронично травмиране, с развитие на <strong>дискови протрузии и пролапси</strong>. По-рядко причините са травматични, токсо-инфекциозни и неопластични.</p><p>Най-често заболяването се развива между <strong>30–50-годишна възраст</strong>. <strong>Дисковите хернии в лумбалната област</strong> са най-честата причина за развитие на радикулит.</p><h2>Клинична картина</h2><p>Не всяка дискова херния се проявява със субективна симптоматика. В около <strong>35–40%</strong> от случаите тя може да протече асимптомно.</p><ol><li><strong>Спонтанна паравертебрална болка</strong> — много силна болка в областта на кръста, която е най-характерният възбуден сетивен симптом при острия дискогенен процес. Обикновено се развива внезапно поради херниране на диска и притискане на коренчето. Свързва се с иритация на дуралния сак, лигаментите и дислокация на интервертебралните стави.</li><li><strong>Провокиране на болката</strong> — болката се провокира при притискане в <strong>точките на Вале</strong>, паравертебрално на <strong>3 cm</strong> от срединната линия и по хода на седалищния нерв. Провокира се и при разтягане на седалищния нерв чрез <strong><span class=\"editor-note\" data-note=\"**Симптомът на Ласег** е проба за дразнене/увреда на **седалищния нерв** или лумбосакралните коренчета.\nИзследва се чрез повдигане или екстензия на засегнатия крак. При **положителен симптом на Ласег** се появява силна болка по хода на опънатия **седалищен нерв**, най-често от кръста към седалището и задната част на крака.\nИзползва се при съмнение за **лумбосакрална радикулопатия/ишиас**, особено при дискова херния.\n![Image](https://files.coursebook.lol/Fenroll/2026-05-12/text-editor-images/2026/05/1778574540684-image.png &quot;width=100%&quot;)\" id=\"note-1778574475714-2\">симптома на Ласег</span></strong>. Той се получава, когато засегнатият крак се свие в колянната и тазобедрената става и след това се екстензира. При положителен симптом се появява силна болка по хода на опънатия седалищен нерв.</li><li><strong>Отпадни сетивни прояви</strong> — проявяват се по дерматомен тип. <strong><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fdermatomes-chart.com%2Fwp-content%2Fuploads%2F2023%2F01%2Fan-mri-report-might-list-a-disc-herniation-but-the-report-often-adds-clinical-correlation-suggested-what-are-the-clinical-correlations-of-a-herniated-disc-said-to-compress-the-l4-l5-or-13.png&amp;f=1&amp;nofb=1&amp;ipt=1db44e661cd74d51764d03d319ef839f4c59d06c1fbb8a28733e5887592e58be &quot;width=100%&quot;)\" id=\"note-1778574609499-3\">Хипестезия по дерматом S1</span></strong>, който обхваща като лента последните пръсти и върви латерално нагоре към бедрото, е характерна за дискова херния на ниво <strong>L5–S1</strong>. <strong>Хипестезия по дерматом L5</strong> се установява при дискова херния <strong>L4–L5</strong>; този дерматом обхваща големия пръст и се движи нагоре и латерално.</li><li><strong><span class=\"editor-note\" data-note=\"**Вертебрален синдром** означава засягане на гръбначния стълб и околните мускули при лумбосакрална радикулопатия.\n* **Паравертебрална ригидност** — стягане и болезнен спазъм на мускулите около гръбначния стълб.\n* **Рефлекторна сколиоза** — изкривяване на тялото настрани като защитна реакция, за да се намали болката и дразненето на нервното коренче.\" id=\"note-1778574649750-4\">Вертебрален синдром</span></strong> — <strong>паравертебралната ригидност</strong> и <strong>рефлекторната сколиоза</strong> са много характерни симптоми.</li><li><strong>Двигателни разстройства</strong> — може да се наблюдават мускулна слабост, хипотония и хипотрофия на мускулите в съответния миотом.</li></ol><p>При дискова херния <strong>L5–S1</strong> се засяга <strong>S1 коренчето</strong> и се уврежда тибиалната група мускули. Описва се позиция <strong><span class=\"editor-note\" data-note=\"**Еквиниварус**, това означава позиция с:\n- **еквинус **= плантарна флексия;\n- **варус **= завъртане навътре.\n![Image](https://files.coursebook.lol/Fenroll/2026-05-12/text-editor-images/2026/05/1778574835057-image.png &quot;width=100%&quot;)\" id=\"note-1778574899735-6\">еквиниварус</span></strong>, но клинично водещо е нарушението на <strong>плантарната флексия</strong> — болните не могат да ходят на пръсти.</p><p>При дискова херния <strong>L4–L5</strong> се получава пареза на перонеалната група мускули (<strong><span class=\"editor-note\" data-note=\"Синоним: **n. peroneus**\n![Image](https://external-content.duckduckgo.com/iu/?u=http%3A%2F%2Fwww.zol.be%2Fsites%2Fdefault%2Ffiles%2Fdeelsites%2Fneurochirurgie%2Fnfp-gevoelsstoornissen_bij_n._fibularis_aantasting.png&amp;f=1&amp;nofb=1&amp;ipt=2fcdbbd52daf5073c9fbf718e0b2a41e6dd8b0d8984154a93cce330e68a6ee9a &quot;width=100%&quot;)\" id=\"note-1778574963514-7\">n. fibularis</span></strong>) поради засягане на <strong>L5 коренчето</strong>. Болният не може да направи дорзална флексия със стъпалото и да стъпва на пети. В някои случаи двигателните симптоми могат да са водещи или да се проявят само с мускулна хипотония.</p><ol><li><strong>Рефлексни разстройства</strong> — при дискова херния <strong>L5–S1</strong> със засягане на <strong>S1 коренче</strong> се развива <strong>ахилова хипо- или арефлексия</strong>.</li><li><strong>Автономни разстройства</strong> — може да се наблюдават цианоза, променена кожна температура, суха или влажна кожа.</li></ol><h2>Изследване и диагноза</h2><p>Стандартните рентгенови снимки показват дегенеративните промени: снижение на диска на съответното ниво, локални остеофити по предните или задните ръбове на прешлените, сколиоза на гръбначния стълб и др.</p><p><strong>Компютърната томография (КТ)</strong> и <strong>магнитно-резонансната томография (МРТ)</strong> имат основно значение за поставяне на диагнозата. Те изобразяват <strong>дисковата протрузия или пролапс</strong>, стесняването на интервертебралния отвор и гръбначния канал, състоянието на меките тъкани около тях и други промени на дисковете и прешлените.</p><p>С <strong>МРТ</strong> се вижда целият гръбначен канал в сагитален план и наличието на дискови пролапси и на други нива.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 47. Дискова херния.</h1><p>Начало</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 48. Неврит на лицевия нерв.</h1><p>Най-честата причина за засягане на лицевия нерв е <strong>първичен идиопатичен възпалителен процес</strong>, свързан с простуден и токсо-инфекциозен фактор. Заболяването се среща най-често през студените месеци и след експозиция на главата на студово въздействие. Допълнителен съдействащ фактор е конституционално по-тесен костен канал на лицевия нерв.</p><p><strong>Парализата на Бел</strong> представлява първична идиопатична периферна парализа на лицевия нерв. Тя е форма на неврит/невропатия на <strong>n. facialis</strong>, но не всеки неврит на лицевия нерв е парализа на Бел.</p><h2>Етиология</h2><p><strong>Симптоматичен неврит / невропатия на n. facialis</strong> може да се наблюдава при много заболявания:</p><ul><li>инфекциозни: грип, <strong>herpes simplex</strong>, полиомиелит, <strong>HIV инфекция</strong>;</li><li>възпалителни процеси по съседство: отит в средното ухо, мастоидит, <strong>herpes zoster инфекция</strong> и др.;</li><li>краниални невропатии: <strong>синдром на Guillain-Barré</strong>, диабетна невропатия, Лаймска болест, васкулити и др.;</li><li>компресия на нерва от тумори в понтоцеребеларния ъгъл — неврином на <strong>n. statoacusticus</strong>, менингеом, базални тумори, аневризми на базиларната артерия и др.</li></ul><h2>Клинична картина</h2><p>Заболяването започва остро, най-често след простуден момент, но понякога и без провокиращ фактор. Най-честата локализация на увредата е в костния канал на нерва. Обикновено болният се събужда с лицева парализа или тя се развива постепенно за около <strong>24 часа</strong>. Много рядко може да има двустранен неврит.</p><p>В зависимост от топиката на лезията се установяват следните симптоми от страна на лицевия нерв и съпровождащите го влакна на <strong>n. intermedius</strong>:</p><ol><li><strong>Парализа на цялата лицева половина</strong> от засегнатата страна — болният не може да набръчка челото, не може да затвори плътно клепача на окото (<strong>lagophthalm</strong>). Появява се <strong>симптом на Bell</strong> — при опит за затваряне на клепача очната ябълка се извърта нагоре. Устният ъгъл е увиснал. Болният не може да покаже зъбите си, да надуе бузата или да свирне с уста. При хранене течностите изтичат от парализирания устен ъгъл, а храната се задържа между зъбите на същата страна.</li><li><strong>Намалена слъзна секреция</strong> на съответното око.</li><li><strong>Хиперакузис</strong> поради лезия на <strong>n. stapedius</strong>.</li><li><strong>Нарушение на вкуса</strong> в предните <strong>две трети</strong> на езика.</li><li><strong>Болки или парестезии</strong> в областта зад ухото.</li></ol><p>Тези симптоми могат да бъдат изразени в различна степен според тежестта на увредата. При лезия на нерва след излизането му от канала, както и при ядрена увреда на моторното ядро, е налице единствено <strong>моторна симптоматика</strong>.</p><h2>Усложнения</h2><ul><li><strong>контрактури на мускулите</strong>;</li><li><strong>синкинезии</strong>;</li><li><strong>кератит</strong>.</li></ul><h2>Диагноза</h2><p>Правят се <strong>рентгенови снимки на пирамидната кост</strong>, <strong>КТ на задна черепна ямка с контрастна материя</strong> или <strong>МРТ</strong> за изключване на туморен процес.</p><h2>Лечение</h2><p>Терапията трябва да започне веднага и включва:</p><ul><li><strong>антиедемни медикаменти</strong> — Mannitol 2–3 по 25–250 ml бързо i.v. за <strong>3–5 дни</strong>;</li><li><strong>антивъзпалителни и антиедемни средства</strong> — кортикостероиди: Methylprednisolon <strong>60–120 mg i.v.</strong> с постепенно намаляване на дозата;</li><li><strong>витамини от група B</strong>;</li><li><strong>физиотерапия и масажи</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 49. Невралгия на троичния нерв.</h1><p>Невралгията на троичния нерв се характеризира със <strong>силна, пристъпна, стрелкаща болка</strong> по хода на един или повече от клоновете на нерва. Най-често се засягат самостоятелно или в комбинация <strong>II и III клон</strong> — <strong>n. maxillaris</strong> и <strong>n. mandibularis</strong>.</p><h2>Етиология</h2><p>Причината за невралгията в <strong>80%</strong> от случаите остава неясна. Тази <strong>идиопатична невралгия</strong> се свързва с наличие на <strong>съдово-нервен конфликт</strong>. Най-често се касае за компресия на нерва от артериални съдове, разположени в близост до началната част на <strong>n. trigeminus</strong>.</p><p>При останалите случаи на <strong>симптоматична невралгия</strong> причина могат да бъдат тумори в задна черепна ямка — в понтоцеребеларния ъгъл, <strong>мултиплена склероза</strong>, процеси на върха на пирамидата, сирингобулбия и др.</p><p>Рядко фокална инфекция от зъбен произход, възпаления на синусите, носа, устната кухина, очите и травми могат да обусловят подобна симптоматика. При <strong>невропатия на n. trigeminus</strong>, освен типичната болка, се установява и отпадна сетивна симптоматика в съответния клон на нерва.</p><h2>Патогенеза</h2><p>Патогенезата на болковия синдром не е напълно изяснена. Предполага се и наличие на <strong>централни, таламични механизми</strong> за поддържане на хроничния болков синдром.</p><h2>Клинична картина</h2><ol><li><strong>Болков пристъп</strong> — започва внезапно. Болката е силна, със стрелкащ характер и наподобява преминаване на електрически ток. Излъчва се по хода на засегнатия клон на нерва или по хода и на трите клона. Болката е краткотрайна — секунди, рядко до минута или повече. Обикновено е едно от най-жестоките болкови изживявания и може да бъде съпроводена от <strong>болезнен тик</strong> на мускулатурата на съответната лицева половина.\nБолката може да се провокира от външни фактори — въздушно течение, хранене, силен шум или светлина и др.</li></ol><ol><li value=\"2\"><strong>Провокиране на болките</strong> — установяват се болки при притискане на <strong>точките на Вале</strong>.</li><li><strong>Автономни разстройства</strong> — обикновено са вазомоторни разстройства и промени в потоотделянето на засегнатата страна. В късните стадии може да се стигне до общо отслабване на индивида поради хроничните мъчителни болки и отказа от храна, тъй като храненето провокира болковия синдром.</li></ol><h2>Диагноза</h2><p>Диагнозата се базира изцяло на <strong>клиничната картина</strong>. Изследванията се провеждат за изясняване на етиологията — <strong>симптоматична или идиопатична невралгия</strong>, както и за изключване на друга патология с подобна клиника.</p><h2>Диференциална диагноза</h2><p>Диференциална диагноза се прави с:</p><ul><li><strong>Неврит на n. trigeminus</strong> — при него се установява и отпадна сетивна, евентуално двигателна симптоматика при засягане на <strong>n. mandibularis</strong>, с хипестезия за повърхностната сетивност по хода на трите клона или само по един от тях.</li><li><strong>Невралгия на n. glossopharyngeus</strong>.</li><li><strong>Мигрена</strong>.</li></ul><h2>Лечение</h2><p>Медикаментозното лечение включва:</p><ul><li><strong>антиконвулсанти</strong> като средство на избор: <strong>Carbamazepine / Tegretol</strong> 3 × 200–400 mg, <strong>Phenytoin</strong> 3 × 100–200 mg, <strong>Topiramate / Topamax</strong> 2 × 100 mg и др.;</li><li><strong>нестероидни противовъзпалителни средства</strong> като Aspirin, Paracetamol, Indomethacin и др. — имат слаб ефект;</li><li><strong>блокади на клоновете на нерва</strong> или на <strong>gangl. semilunare</strong> с алкохол, фенол, глицерол — ефектът се постига за няколко месеца;</li><li><strong>оперативни интервенции</strong> — микроваскуларна декомпресия на нерва, ризотомия на <strong>n. trigeminus</strong>.</li></ul><h2>Прогноза</h2><p><strong>Идиопатичната невралгия</strong> е хронично заболяване, което може да продължи цял живот и постепенно довежда болните до физическо и психическо изтощение. Поради тази причина трябва упорито да се търсят причините за заболяването и съответно да се лекуват.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 50. Полиневрити и полиневропатии. Синдром на Гилен-Баре.</h1><p><strong>Полиневропатиите</strong> са заболявания, които се характеризират с двустранни лезии на множество периферни нерви вследствие на интоксикации, инфекциозни, неопластични, метаболитни и други системни заболявания.</p><h2>Класификация и етиология</h2><p>Полиневропатиите могат да се разделят на <strong>вродени</strong> и <strong>придобити</strong>.</p><p>Придобити полиневропатии могат да се развият при голям брой заболявания и интоксикации. Според клиничния ход те се разделят на:</p><ul><li><strong>остри</strong>;</li><li><strong>подостри</strong>;</li><li><strong>хронични</strong>.</li></ul><p>Според симптоматиката биват:</p><ul><li><strong>сензорни</strong>;</li><li><strong>моторни</strong>;</li><li><strong>автономни</strong>;</li><li><strong>смесени полиневропатии</strong>.</li></ul><h2>Патоморфология</h2><p>Хистологично се установяват следните промени:</p><ol><li><strong>Сегментна демиелинизация</strong> — огнищни лезии на демиелинизация, периваскуларни инфилтрати от лимфоцити, моноцити и макрофаги.</li><li><strong>Аксонална дегенерация / аксонопатия</strong>.</li><li><strong>Валерова дегенерация</strong> — увреда на аксона и неговата миелинова обвивка.</li><li><strong>Невронална дегенерация / невронопатия</strong> — първична деструкция на клетъчното тяло на невроните с дегенерация на техните аксони.</li></ol><h2>Клинична картина</h2><p>Клиничната картина зависи от етиологията, тежестта и разпространението на перифернонервната лезия, както и от продължителността на действие на увреждащия фактор.</p><p>Заболяването може да започне във всяка възраст. Началото може да бъде <strong>остро, подостро или хронично</strong>. Повечето полиневропатии са субакутни или хронични. Някои хронични полиневропатии имат <strong>хронично-ремитентно протичане</strong> с пристъпи и ремисии за различен период.</p><ol><li><strong>Сетивни симптоми</strong> — първите и най-чести симптоми на полиневропатиите. Възбудните симптоми включват болки с остро начало, които могат да се провокират при натиск и при симптоми на разтягане. Почти винаги има <strong>дистални парестезии</strong>. Симптомите започват първо в долните крайници, а след това ангажират и горните. Налице е <strong>симетрична дистална хипестезия</strong> за повърхностна сетивност.</li><li><strong>Моторни симптоми</strong> — отпадни прояви. Развива се <strong>вяла пара- или квадрипареза до плегия</strong>. Вялите парези са симетрични, започват от долните крайници и прогресират проксимално. По-рядко могат да започнат проксимално, например при порфиринова полиневропатия. При хроничните полиневропатии вялите парези се развиват бавно и се съпровождат с <strong>трофични разстройства на мускулите</strong>. При острите полиневропатии могат да се засегнат <strong>черепно-мозъчни нерви</strong>.</li><li><strong>Рефлексни нарушения</strong> — рефлексите отслабват или липсват.</li><li><strong>Автономни симптоми</strong> — могат да бъдат водещи: <strong>ортостатична хипотония</strong>, нарушена регулация на АН, тахикардия, ФИТ нарушения и тазово-резервоарни смущения.</li></ol><h2>Остра възпалителна демиелинизираща полирадикулоневропатия — синдром на Guillain-Barré</h2><p>Заболяването се характеризира с <strong>остро начало</strong> и прогресиращо засягане на периферните нерви и коренчета — <strong>полирадикулоневропатия</strong>, с тенденция за асцендиране на симптомите.</p><p>Представлява <strong>автоимунно заболяване</strong> с развитие на антитела към базичния протеин на миелина на периферните нерви. Начало на сенсибилизацията и отключване на автоимунния процес могат да бъдат вирусни или други инфекции. При <strong>75%</strong> от пациентите <strong>1–4 седмици</strong> преди началото на заболяването е прекарана респираторна или гастроинтестинална инфекция.</p><h2>Клинична картина при синдром на Guillain-Barré</h2><p>Клиничната картина се развива остро или подостро.</p><ol><li><strong>Сетивни симптоми</strong> — първите симптоми често са спонтанни болки и парестезии в крайниците. Постепенно се установява дистално засилваща се <strong>хипестезия за всички видове сетивност</strong>.</li><li><strong>Мускулна слабост</strong> — водещ клиничен симптом е прогресиращата <strong>симетрична мускулна слабост</strong>, която започва от дисталните отдели на долните крайници и впоследствие асцендира към тялото и горните крайници.</li><li><strong>Рефлексни нарушения</strong> — налице е дистална или генерализирана <strong>сухожилна хипо- до арефлексия</strong>.</li><li><strong>Автономна симптоматика</strong> — синусова тахикардия, хипертония, ортостатична хипотония, редуване на артериална хипертония с хипотония.</li></ol><p>Пълното развитие на симптоматиката при <strong>50%</strong> от пациентите настъпва в рамките на <strong>2 седмици</strong>.</p><h2>Диагноза</h2><p>Диагнозата се насочва от следните прояви:</p><ul><li><strong>прогресираща, асцендираща, симетрична, предимно дистална, вяла пареза</strong>;</li><li><strong>дистална или обща сухожилна хипо- до арефлексия</strong>;</li><li>леки сетивни симптоми — парестезии, дистална хипестезия до анестезия, болки по хода на периферните нерви;</li><li>лезия на <strong>черепно-мозъчни нерви</strong>;</li><li><strong>автономни симптоми</strong>;</li><li>липса на температура.</li></ul><h2><span class=\"editor-note\" data-note=\"### **ЕМГ**\nПоказва дали има увреда на периферните нерви и дали тя е предимно **демиелинизираща** или **аксонална**. Помага да се оцени тежестта и разпространението на увредата.\n### **Ликворно изследване**\nОсобено важно при съмнение за **синдром на Guillain-Barré**. Търсят се промени, които подкрепят възпалителна полирадикулоневропатия.\n### **Биопсия на периферен нерв**\nИзползва се по-рядко, когато трябва да се уточни морфологичният тип увреда — например **демиелинизация**, **аксонална дегенерация**, възпалителни или други промени.\n### **Очни дъна**\nПравят се като част от неврологичната оценка, за да се търсят данни за съпътстващи промени и да се изключат други процеси, които могат да наподобяват или усложняват картината. Накратко: **ЕМГ доказва и типизира увредата**, **ликворът подпомага диагнозата при възпалителни форми**, **биопсията уточнява морфологията**, а **очните дъна помагат в общата неврологична оценка**.\" id=\"note-1778576144530-8\">Изследвания</span></h2><p>Изследванията включват:</p><ul><li><strong>ЕМГ</strong>;</li><li><strong>ликворно изследване</strong>;</li><li><strong>биопсия на периферен нерв</strong>;</li><li>изследване на <strong>очни дъна</strong>.</li></ul><h2>Терапия</h2><ol><li><strong>Мониториране на виталните функции</strong> — при тежките форми със засягане на дихателната или булбарната мускулатура е наложителна готовност за реанимационни мероприятия и грижи.</li><li><strong><span class=\"editor-note\" data-note=\"**Плазмафереза** е метод, при който от кръвта се отделя и отстранява **плазмата**, а клетъчните елементи се връщат обратно в организма.\nПри **синдром на Guillain-Barré** се използва, защото премахва от плазмата патологични фактори като **антитела и възпалителни медиатори**, които участват в автоимунното увреждане на периферните нерви.\" id=\"note-1778576199449-9\">Плазмафереза</span></strong> — с доказана ефективност. Стандартната схема включва <strong>4–6 процедури през ден</strong>.</li><li><strong>Високи дози имуноглобулин</strong> — прилага се интравенозно в доза <strong>0,4 g/kg</strong> за <strong>5 последователни дни</strong>.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 51. Вирусни менингити.</h1><p>Повечето вирусни менингити се явяват следствие на <strong>системни вирусни инфекции</strong> и затова се означават като <strong>вторични менингити</strong>. Поради характерната ликворна находка се наричат още <strong>серозни, лимфоцитарни менингити</strong>.</p><p>Сравнително малко вирусни инфекции обуславят развитие на <strong>първични менингити</strong>. По хематогенен път се разпространяват <strong>Cytomegalovirus</strong>, вирусът на <strong>Epstein-Barr</strong> и ентеровирусите. По неврогенен път се разпространяват вирусите на <strong>Herpes simplex</strong>, <strong>rabies</strong>, полиовирусите и др.</p><p>Протичането на повечето вирусни менингити е <strong>остро</strong>, рядко подостро или хронично.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Първични ентеровирусни менингити</h2><p><strong>Ентеровирусите</strong> са едни от най-честите причинители на <strong>серозни менингити</strong> при човека. Към тази група спадат <strong><span class=\"editor-note\" data-note=\"**Coxsackie A** — група ентеровируси, които се размножават в стомашно-чревния тракт. По-често се свързват с инфекции на кожа, лигавици и горни дихателни пътища, но могат да участват и в системни вирусни инфекции.\n**Coxsackie B** — група ентеровируси, близки до Coxsackie A. По-често се свързват със засягане на мускули, сърце и нервна система. Могат да протичат с фебрилитет, болки и общоинфекциозни прояви.\" id=\"note-1778576362698-10\">Coxsackie A и B</span></strong>, <strong><span class=\"editor-note\" data-note=\"**ECHO вируси** — ентеровируси, чието име идва от Enteric Cytopathic Human Orphan viruses. Размножават се в чревния тракт и често причиняват неспецифични вирусни инфекции с температура, обриви или стомашно-чревни прояви.\" id=\"note-1778576375361-11\">ECHO</span></strong> и <span class=\"editor-note\" data-note=\"**Полиомиелитни вируси** — ентеровируси, причинители на полиомиелит. Те могат да засегнат нервната система, особено моторните неврони, и при тежки случаи да доведат до вяли парези или парализи.\" id=\"note-1778576386565-12\"><strong>полиомиелитните</strong></span> вируси.</p><h3>Епидемиология</h3><p>Тези заболявания се развиват на малки епидемии, обикновено през летните месеци и сред население с лоши хигиенни условия. Вирусите се развиват в стомашно-чревния тракт и се разпространяват с мръсни води по орален и въздушно-капков път.</p><h3>Клинична картина</h3><p>Клиничната картина е неспецифична и по нея трудно може да се прецени причинителят. Обикновено менингитът започва с висока температура, силно главоболие, гадене, повръщане и развитие на типичен <strong><span class=\"editor-note\" data-note=\"**Менингеален синдром** е комплекс от симптоми при дразнене на мозъчните обвивки.\nТипични находки при неврологичен статус:\n1. **Вратна ригидност** — затруднено или болезнено пасивно сгъване на главата към гърдите.\n2. **Симптом на Kernig** — при сгъната тазобедрена и колянна става не може да се разгъне подбедрицата без болка/съпротивление.\n3. **Симптом на Brudzinski** — при пасивно сгъване на главата към гърдите настъпва неволно сгъване на долните крайници.\n4. **Фотофобия и хипералгезия** — непоносимост към светлина и повишена болезненост/чувствителност.\nЧесто се съчетава със **силно главоболие**, **гадене**, **повръщане** и **фебрилитет**.\" id=\"note-1778576434377-13\">менингеален синдром</span></strong>.</p><p><strong>ECHO вирусните менингити</strong> причиняват серозни менингити, които клинично не се различават съществено от тези при Coxsackie вирусните инфекции. Често се съпровождат със стомашно-чревни симптоми — болки в корема, гадене, повръщане, диарии и др.</p><p>Лумбалният ликвор показва <strong><span class=\"editor-note\" data-note=\"**Плеоцитоза** означава **повишен брой клетки в ликвора**.\nНай-често се установява при възпалителни заболявания на ЦНС, особено при **менингити** и **енцефалити**.\" id=\"note-1778576566052-14\">плеоцитоза</span> от смесен характер</strong> — бързопреходно увеличение на полинуклеарните левкоцити, последвано от <strong>лимфоцитоза 25–250 × 10<sup>6</sup>/l</strong>, и леко увеличение на белтъка.</p><h3>Диагноза и лечение</h3><p>Диагнозата се поставя чрез доказване на вируса в <strong>ликвора</strong>, изпражненията или носогърления секрет.</p><p>Терапията е изцяло симптоматична — <strong>аналгетици</strong>, витамини, понякога дехидратиращи средства.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лимфоцитарен хориоменингит</h2><p><strong>Лимфоцитарният хориоменингит</strong> се причинява от вируса на <strong>Armstrong-Lillie</strong>. Естественият резервоар на заразата са гризачи, като заразяването се осъществява по въздушно-капков и орален път.</p><h3>Клинична картина</h3><p>Клиничната картина протича в две фази — <strong>грипоподобна</strong> и <strong>менингитна</strong>.</p><ol><li><strong>Грипоподобна фаза</strong> — заболяването започва с фебрилитет, разтрисане, миалгии и артралгии, ангина и диариен синдром.</li><li><strong>Менингитна фаза</strong> — развива се около една седмица след началото на заболяването. След кратка ремисия температурата отново се покачва до <strong>39–40°</strong>, развиват се силно главоболие и <strong>менингеален синдром</strong>.</li></ol><p>Понякога може да се добави <strong>енцефалитна симптоматика</strong> с огнищна неврологична симптоматика и лезии на черепно-мозъчни нерви. Често се срещат психични симптоми — психомоторна възбуда или психоза.</p><p>Ликворният синдром е с <strong>плеоцитоза с 95–100% лимфоцити</strong> и лека до умерена <strong>хиперпротеинрахия</strong>.</p><h3>Диагноза, лечение и прогноза</h3><p>Диагнозата се поставя <strong>серологично</strong>. Лечението е симптоматично, както при другите вирусни менингити.</p><p>Продължителността на заболяването е <strong>3–4 седмици</strong>, след което болните се възстановяват напълно.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 52. Бактериални менингити.</h1><h2>Менингококов менингит</h2><p>Менингококовата инфекция клинично може да се изяви като <strong>назофарингит</strong>, <strong>гноен менингит</strong> и <strong>менингококов сепсис</strong>. Менингококовият менингит протича с тежка септична картина, <strong>гноен ликворен синдром</strong> и висок леталитет.</p><h2>Етиология</h2><p>Причинителят е <strong>Neisseria meningitidis</strong>.</p><h2>Патогенеза и патоанатомия</h2><p>Разпространението е предимно <strong>хематогенно</strong>, но е възможно и директно преминаване през назофарингса.</p><p>Възпалителният процес започва с <strong>хиперемия на менингите</strong>, дилатация и увеличен пермеабилитет на съдовете, както и формиране на възпалителен ексудат с голямо количество фибриноген.</p><p>Развиват се клетъчни инфилтрати по менингите, около съдовете, коренчетата на черепно-мозъчните и спиналните нерви. Те са изградени от неутрофили, лимфоцити, макрофаги и плазматични клетки.</p><p>Макроскопски се установява <strong>обилен гноен ексудат</strong> по конвекситета на мозъка и около мозъчните цистерни. Менингите са задебелени и хиперемирани. Поради нарушена резорбция на ликвора се развива <strong>хидроцефалия</strong>.</p><p>Засягането на коренчетата на черепно-мозъчните нерви от гнойния ексудат води до лезия на слуховия, лицевия и очедвигателните нерви с нарушение на слуха и развитие на парези на лицевите и очните мускули.</p><h2>Клинична картина</h2><p>Заболяването започва остро с разтрисане и висока температура до <strong>40°</strong>. Често бързо прогресира нарушение в съзнанието до кома.</p><p>Развива се тежък <strong>синдром на менингорадикулерно дразнене</strong> с главоболие, повръщане, вратна ригидност, положителни симптоми на <strong>Керниг</strong> и <strong>Брудзински</strong>. Може да има епилептични пристъпи и лезии на <strong>n. facialis</strong> и <strong>n. oculomotorius</strong>.</p><p>При възрастните хора често се изявяват психотични състояния — делири и психози. Менингококовият менингит в над <strong>50%</strong> от случаите се съчетава с кожни обриви — макуло-папулозни, петехиални или хеморагично-некротични.</p><h2>Клинични форми</h2><p><strong>Хронично-рецидивираща форма</strong> на заболяването понастоящем е много рядка. Дължи се на непълноценно лечение.</p><p><strong>Менингококов сепсис</strong> може да бъде остър, свръхостър и хроничен. При острия заболяването започва внезапно с втрисане и температура до <strong>40°</strong>, кардиоциркулаторна слабост с тахикардия и хипотония, тахипнея и олигоанурия. Появява се петехиален генерализиран обрив, който преминава в <strong>хеморагично-некротичен</strong>.</p><p>При свръхострия сепсис клиничните прояви се задълбочават много бързо, нарушава се съзнанието и изходът най-често е фатален.</p><p><strong>Синдромът на Waterhouse-Friderichsen</strong> се дължи на хеморагии и некроза в двете надбъбречни жлези. Среща се в <strong>10%</strong> от случаите и предизвиква тежка остра надбъбречна недостатъчност с артериална хипотония, водно-електролитни нарушения, петехиални кръвоизливи и бърза смърт, преди менингеалният синдром да се разгърне.</p><p>Фатално усложнение е развитието на <strong>дисеминирана интравазална коагулация — ДИК синдром</strong>.</p><h2>Диагноза</h2><p>Диагнозата се насочва от клиничната картина на <strong>тежък остър менингит</strong>, често с нарушено съзнание.</p><p>Изследването на лумбалния ликвор показва, че той изтича под повишено налягане и е <strong>гноен</strong>. При престой на открито може да се образува фибринова мрежа. Микроскопски се установява висока <strong>плеоцитоза</strong>, предимно от неутрофилни гранулоцити.</p><p><strong>Грам-негативният диплокок</strong> се установява при микроскопия интра- и екстрацелуларно. Белтъчното съдържание е силно повишено — <strong>хиперпротеинрахия</strong>. Имуноглобулините също са повишени. Съдържанието на глюкоза е силно намалено — под <strong>1 mmol/l</strong>.</p><p>Посявката на ликвор е важна за диагнозата и за определяне на чувствителността на бактерия към антибиотици. Изследват се и <strong>хемокултури</strong>.</p><p><strong>КТ</strong> и <strong>МРТ</strong> показват някои от усложненията на менингита — венозни флеботромбози, исхемични огнища, мозъчен оток, остра хидроцефалия и др.</p><h2>Диференциална диагноза</h2><p>Диференциалната диагноза се прави с <strong>вторични остри бактериални менингити</strong>. При тях са важни анамнестичните данни за друго възпалително, най-често гнойно огнище в организма:</p><ul><li>отити;</li><li>синузити;</li><li>тонзилити;</li><li>зъбни грануломи;</li><li>абсцеси;</li><li>пневмония;</li><li>ендокардит;</li><li>фурункули;</li><li>карбункули;</li><li>остеомиелит и др.</li></ul><p>Най-честите причинители са стрептококи, стафилококи, пневмококи, коли-бактерии и друга грам-негативна флора.</p><p>Бактериален менингит може да се получи и при нарушена асептика при лумбална пункция или след мозъчни оперативни интервенции — <strong>ятрогенно</strong>.</p><h2>Терапия</h2><p>Лечението включва <strong>цефалоспорини трето поколение</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 53. Туберкулозен менингит.</h1><p><strong>Туберкулозният менингит</strong> е тежък <strong>серофибринозен лептоменингит</strong> със субакутно или хронично протичане.</p><h2>Етиология</h2><p>Причинява се от <strong>Mycobacterium tuberculosis</strong>. Предава се по въздушно-капков път и се разпространява в организма по лимфен и кръвен път до ЦНС, където се образуват малки туберкулозни грануломи — <strong>туберкули</strong>, под епендима на субарахноидното и вентрикуларното пространство.</p><p>Възможно е и директно хематогенно метастазиране от друго, най-често белодробно туберкулозно огнище.</p><h2>Патоанатомия</h2><p>Макроскопски менингите са мътни и хиперемирани. Установява се <strong>жълтеникав серофибринозен ексудат</strong>, предимно по мозъчните гънки, задната черепна ямка и базалните цистерни на мозъка.</p><p>По хода на мозъчните съдове могат да се видят множество <strong>милиарни туберкули</strong>. Установяват се още <strong>мозъчен едем</strong>, вътрешна и външна <strong>хидроцефалия</strong>, понякога и мозъчно вклиняване.</p><p>Могат да се наблюдават артериални и венозни тромбози с развитие на <strong>мозъчни инфаркти</strong>. При хронифициране се откриват масивни фиброзни сраствания — <strong>адхезии</strong>, особено по базата на мозъка, с обхващане на коренчетата на черепно-мозъчните нерви, нарушен ликворен дренаж и развитие на хидроцефалия.</p><h2>Клинична картина</h2><p>В началния продромален стадий болният се оплаква от общо неразположение, астения, безапетитие, отслабване на тегло, субфебрилна температура, несистемно главоболие, нощно изпотяване и др. Този период продължава <strong>2–3 седмици</strong>.</p><p>След това заболяването се манифестира с:</p><ol><li><strong>Висока температура</strong>.</li><li><strong>Синдром на менингорадикулерно дразнене</strong> — главоболие, гадене и повръщане, фото- и фонофобия, вратна ригидност, симптоми на <strong>Kernig</strong>, <strong>Brudzinski</strong> и др.</li><li><strong>Очедвигателни и други огнищни симптоми</strong> — птоза, диплопия, засягане на лицевия и слуховия нерв.</li><li><strong>Вегетативни разстройства</strong> — чести са брадикардия, кожни вазомоторни разстройства и колапси.</li><li><strong>Психотична симптоматика</strong> — може да се наблюдават психомоторна възбуда, делири и др.</li><li><strong>Количествени нарушения на съзнанието</strong> — помрачение на съзнанието, сомнолентност, сопор, а в терминален стадий и кома.</li></ol><h2>Диагноза</h2><p>В началото диагнозата е предимно <strong>клинична</strong>, базирана на ликворното изследване и търсене на микобактерии в ликвора.</p><p>Ликворът изтича под високо налягане, безцветен или жълтеникав. Цитологичното изследване показва <strong>плеоцитоза</strong>, понякога и <strong>еритроцитрахия</strong> — кървав ликвор.</p><p>При диференциалното броене се установява пъстра картина. В ранните стадии преобладават неутрофилните гранулоцити, а по-късно плеоцитозата е предимно за сметка на лимфоцити, макрофаги и плазматични клетки. При хронифициране е налице <strong>лимфоцитоза</strong>.\nБелтъчното съдържание е увеличено в зависимост от стадия и наличието на усложнения. Имуноглобулините са силно увеличени и нерядко се установява <strong>олигоклонална хипергамаглобулинрахия</strong>. Количеството на захарта и хлоридите в ликвора е намалено.</p><p>Лумбални пункции се правят през целия период на лечението. Болният се смята за практически оздравял само ако броят на клетките в ликвора напълно се нормализира.</p><h2>Усложнения</h2><ul><li><strong>рецидиви</strong> при некачествено лечение;</li><li>лезия на <strong>n. opticus</strong>;</li><li><strong>симптоматична епилепсия</strong>;</li><li>психични промени.</li></ul><h2>Лечение</h2><p>Лечението включва <strong>туберкулостатици и антибиотици</strong> в течение на няколко месеца, <strong>кортикостероиди</strong>, симптоматични лекарства, <strong>витамин B6</strong> и <strong>витамин A</strong>.</p><h2>Протичане и прогноза</h2><p>Протичането и прогнозата зависят от тежестта на заболяването, своевременното и адекватно лечение, продължителността на специфичната терапия и общото преморбидно състояние на болния.</p><p>При навреме поставена диагноза и правилно лечение оздравяване може да се очаква след <strong>6 до 12 месеца</strong>. Обикновено острите прояви преминават след <strong>1–2 месеца</strong> и болните се чувстват добре. Въпреки това ликворният синдром персистира и пребързаното спиране на терапията води след няколко седмици до рецидив.</p><p>При неблагоприятно протичане може да се стигне до арахноиден блок на базалните цистерни с тежки нарушения в ликворния дренаж, вътрешна хидроцефалия, повишено вътречерепно налягане и <strong>застойна папила</strong>.</p><p>В крайните стадии при нелекувани болни се развива <strong>децеребрационна ригидност</strong> с екстензорни гърчове, кома и летален изход. Ликворът показва наличие на много белтък и тенденция към <strong>белтъчно-клетъчна дисоциация</strong>.</p><h2>Диференциална диагноза</h2><p>Диференциалната диагноза се прави предимно с други хронични менингити — бактериални, микотични и паразитни.</p><p>За отдиференцирането им, освен клиниката и ликворния синдром, решаващо значение имат <strong>микробиологичното изследване</strong> и <strong>серологичните реакции</strong>, включително <strong>PCR</strong>, за изясняване на причинителя.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 54. Мозъчен абсцес. Паразитози на нервната система.</h1><h2>Мозъчни паразитози - Мозъчен ехинокок</h2><h3>Етиология</h3><p>При човека ехинококът е тъканна инфекция, причинена от ларвите на лентовидния паразит <strong>Echinococcus granulosus</strong> — кучешка тения.</p><p>Инфектирането се осъществява чрез директен контакт с кучета или при консумация на вода и хранителни продукти, заразени с яйца на тенията от кучешки изпражнения.</p><h3>Патогенеза</h3><p>В стомаха на човека зародишите се освобождават от обвивката си и по кръвен или лимфен път се разпространяват в други органи, където образуват кисти. По хода на венозната кръв те най-често достигат и се задържат в черния дроб.</p><p>Ако преминат през него, достигат до белите дробове, а чрез артериалната кръв могат да се разпространят практически навсякъде в организма. Мозъкът се засяга в около <strong>2%</strong> от случаите.</p><h3>Патоанатомия</h3><p>Ехинококовите кисти са с дебела хитинова обвивка, пълни с прозрачна жълтеникава течност, съдържаща янтарна киселина. Кистите биват:</p><ul><li><strong>еднокамерни / хидатидозни</strong>;</li><li><strong>многокамерни / алвеоларни</strong>.</li></ul><p>Те са с различна големина. Разполагат се по-често дълбоко в хемисферите — централните извивки, фронталния дял, и по-рядко във вентрикулите, малкия и гръбначния мозък.</p><p>В резултат от реактивното възпаление около ехинококовата киста в мозъка се образува дебела няколкослойна капсула. В съседство се откриват огнища на инфарциране.</p><h3>Клинична картина</h3><p>Клиниката е на <strong>пространство-заемащ процес</strong>. Налице са симптоми на повишено интракраниално налягане — главоболие, повръщане, могат да се наблюдават и епилептични пристъпи.</p><p>Огнищните неврологични симптоми зависят от локализацията на кистата. Понякога се наблюдават и психични симптоми. Гръбначномозъчната локализация на кистата дава симптоматика на <strong>спинална компресия</strong>.</p><h3>Диагноза и диференциална диагноза</h3><p>Диагнозата се улеснява от анамнезата за контакт с кучета и пребиваване в райони с висока честота на ехинококоза. Значение има и евентуалното откриване на кисти в други органи.</p><p><strong>Серологичните тестове</strong> са положителни при <strong>60–90%</strong> от болните. <strong>КТ</strong> и <strong>МРТ</strong> са методи на избор за поставяне на диагнозата. Визуализира се добре ограничена, хиподенсна, окръглена формация, без видима капсула.</p><p>В ликвора се откриват лека <strong>плеоцитоза</strong> с еозинофили, <strong>хиперпротеинрахия</strong> и наличие на янтарна киселина. <strong>Биопсичното изследване на кистата е противопоказано</strong>.</p><h3>Лечение</h3><p>При единични кисти и подходяща локализация се препоръчва оперативно лечение с <strong>тотална екстирпация</strong>.</p><p>Предварителното третиране с <strong>Albendazole</strong> или <strong>Mebendazole</strong> може да намали размерите на кистата, риска от интраоперативно дисеминиране на инфекцията и да предотврати алергични реакции.</p><p>При повече от една мозъчна киста се прилага консервативно лечение с посочените медикаменти. При необходимост се провежда симптоматично лечение — антиконвулсанти, аналгетици, противоедемни средства и др.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Мозъчна цистицеркоза</h2><p><strong>Невроцистицеркозата</strong> е най-честата паразитна инфекция на ЦНС. В ендемичните райони тя е и най-честата причина за епилепсия.</p><h3>Етиология</h3><p>Невроцистицеркозата е ларвен или междинен етап на инфекция със свинска тения — <strong>Taenia solium</strong>. Заразяването се осъществява при поглъщане на яйца на тенията с контаминирана храна.</p><h3>Патофизиология</h3><p>В киселата стомашна среда плътната обвивка на яйцето се разтваря. Чрез системното кръвообращение зародишите на паразита се разпространяват в организма.</p><p>В мозъка, след редица промени, зародишите преминават в личинки — <strong>цистицерки / Cysticercus cellulosae</strong>, които живеят от <strong>3 до 30 години</strong>, най-често <strong>3–6 години</strong>.</p><h3>Патоанатомия</h3><p>Цистицерките в мозъка имат везикуларна структура. Изпълнени са с течност, в която е инвагинирана главата — <strong>scolex</strong> — на паразита. Понякога са макрокистозни, мултивезикулни — <strong>Cysticercus racemosum</strong>.</p><p>Кистите се локализират най-често в обвивките и кората на главния мозък. По-рядко са в подкоровите възли, бялото мозъчно вещество и мозъчните вентрикули. Те упражняват механично и токсично въздействие върху мозъчната тъкан.</p><p>Кистите предизвикват дегенеративни промени в нервните елементи и реактивно възпаление. Налице са хиперплазия и пролиферация на глия, както и инфилтриране на мозъчната тъкан с лимфоидни елементи и плазматични клетки.</p><p>Възпалителните промени са по-изразени при мъртвите ларви. Около цистицерка се образува капсула, чиито външни слоеве са инфилтрирани от клетки, предимно плазматични клетки и еозинофили.</p><p>В съдовете се установява ендартериит и периартериит. Мозъчните обвивки са уплътнени, а микроскопски в тях се открива хроничен възпалителен процес. Мозъчните вентрикули са разширени в различна степен.</p><h3>Клинична картина</h3><p>Много рядко невроцистицеркозата може да остане асимптомна. Мозъчните прояви се предизвикват от кистите, калцификатите и възпалителните промени, които те причиняват. Обикновено заболяването има <strong>ремитентно-екзацербиращ ход</strong>.</p><p>Различават се <strong>4 клинични форми</strong>:</p><ol><li><strong>Паренхимна форма</strong> — симптомите се свързват с локализацията на кистите. Кортикалните кисти предизвикват огнищни или генерализирани епилептични пристъпи. Отпадните симптоми — хемипарези, хемианопсия, хемихипестезия, афазия, атаксия — са по-редки. Понякога възникват мозъчни инсулти и деменция. Много рядко в стадия на инфекцията се развива дифузен енцефалит с помрачение на съзнанието до кома.</li><li><strong>Субарахноидна форма</strong> — възниква при руптура или смърт на арахноидна киста или при трансформирането ѝ в рацемозна форма. Тя расте в базалните цистерни и предизвиква обструктивна хидроцефалия. Менингеалните симптоми варират от леко главоболие до хроничен менингит с хидроцефалия. При спинална локализация може да настъпи пълен спинален субарахноиден блок.</li><li><strong>Вентрикулна форма</strong> — обикновено се съчетава със субарахноидната форма. Може да причини обструктивна хидроцефалия. Движението на кистите във вентрикулното пространство може да предизвика <strong>„клапен“ ефект</strong> с интермитентни симптоми.</li><li><strong>Спинална форма</strong> — по-рядка от другите. Обикновено се характеризира със симптоми на шиен екстрамедуларен и торакален интрамедуларен процес.</li></ol><h3>Диагноза и диференциална диагноза</h3><p>Диагнозата трябва да се обсъжда при болни с епилепсия, менингит, повишено интракраниално налягане и анамнеза за контакт с животни или пребиваване в ендемични зони.</p><p>Важно значение има откриването на <strong>калцификати</strong> в мускулите на раменния пояс, тялото и бедрата. Краниографиите показват калцирали цистицерки. <strong>КТ</strong> и <strong>МРТ</strong> визуализират хидроцефалията и мястото на запушването.</p><p>Ликворът може да бъде нормален или с умерена плеоцитоза и повишено налягане. При по-тежки менингити в ликвора има плеоцитоза, обикновено от мононуклеари, <strong>хиперпротеинрахия</strong> и понижено ниво на глюкозата. Повишени са гама-глобулините, особено <strong>IgG</strong>, което насочва към локална имунна продукция.</p><p>Серологичните проби в серума и ликвора — <strong>ELISA, RIF, RPHA</strong> — обикновено са положителни.</p><p>Диференциалната диагноза се прави с други паразитози, фунгален и туберкулозен менингит, мозъчни метастази и други обемни лезии.</p><h3>Лечение</h3><p>За лечение на невроцистицеркозата, особено при активните форми, се прилагат противопаразитни средства: <strong>Praziquantel 50 mg/kg дневно</strong> или <strong>Albendazole 20 mg/kg дневно</strong>.</p><p>Кортикостероиди и антихистамини се прилагат за предотвратяване на тежки възпалителни реакции, хроничен менингит с арахноидит и оток.</p><p>Провежда се и симптоматично лечение с антиконвулсанти, аналгетици и др.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Мозъчен абсцес</h2><p>Мозъчните абсцеси представляват <strong>гнойни възпалителни огнища</strong>, разположени в мозъчното вещество. Те се характеризират с <strong>некроза на паренхима</strong>, обилен гноен ексудат и ограничителна възпалителна капсула.</p><p>Мозъчният абсцес е следствие на прекарано възпалително заболяване или оперативна интервенция. След контрастна материя се оформя тънка хиперденсна капсула, чрез която хиподенсната лезия се разграничава ясно от перифокалния едем.</p><h2>Етиология</h2><p>Мозъчните абсцеси се развиват вследствие на проникване в мозъчния паренхим по съседство или чрез хематогенна дисеминация на различни бактериални, микотични или паразитни инфекциозни агенти. Причинителите най-често са <strong>бактерии</strong>.</p><h2>Патогенеза</h2><p>Основните патогенетични механизми за развитие на мозъчните абсцеси са:</p><ol><li><strong>По съседство</strong></li></ol><p><strong>Отогенни абсцеси</strong> — развиват се при възпалителни процеси в средното ухо и <strong>proc. mastoideus</strong>, обикновено със смесена анаеробна микрофлора. Инфекцията може да проникне директно при развитие на остеомиелит с последващо разпространение към дурата, лептоменингите и мозъчния паренхим.</p><p>Друг възможен механизъм е развитие на тромбофлебит на пиалните вени и дуралните синуси, с инфарциране на мозъчната тъкан и гнойно възпаление. Отогенните абсцеси се локализират най-често в средните и долни отдели на темпоралния дял и в малкомозъчните хемисфери.</p><p><strong>Риногенни / синогенни абсцеси</strong> — развиват се най-често при фронтален синуит и се локализират във фронталния дял. Абсцесите вследствие на възпаление на сфеноидалния синус са локализирани в медиалните отдели на темпоралния дял.</p><ol><li><strong>Хематогенни / метастатични абсцеси</strong></li></ol><p>Най-често първичната инфекция е с белодробен произход. Тези абсцеси се локализират най-често в дисталните отдели на басейна на <strong>a. cerebri media</strong> и обикновено са множествени.</p><ol><li><strong>Директно проникване на инфекцията</strong></li></ol><p>Наблюдава се при открити черепно-мозъчни травми и след неврохирургични интервенции.</p><p>Абсцесите се срещат по-често при имуносупресирани пациенти — болни със СПИН, с неопластични заболявания на терапия с цитостатици и др.</p><h2>Патоморфология</h2><p>Формирането на абсцеса преминава през два основни стадия:</p><ol><li><strong>Локален супуративен енцефалит</strong> — некроза на паренхима на мястото на бактериалната инвазия, възпалителен инфилтрат от сегментоядрени левкоцити и макрофаги, септична тромбоза на съдовете по съседство и интерстициален перифокален оток.</li><li><strong>Формиране на абсцесна капсула</strong> — след около <strong>1–2 седмици</strong> абсцесният център се изпълва с гной, а по периферията започва пролиферация на фибробласти с образуване на гранулационна тъкан. Така се формира абсцесната капсула, която първоначално е изградена от васкуларизирана гранулационна тъкан, а по-късно, при хронифициране, в нея преобладава колагенна съединителна тъкан.</li></ol><h2>Клинична картина</h2><p>В началния енцефалитен стадий се наблюдава изразен <strong>фебрилно-интоксикационен синдром</strong>, общомозъчна симптоматика и огнищен неврологичен дефицит според топиката на възпалителния процес.</p><p>Установяват се:</p><ol><li><strong>Фебрилитет до 39–40°</strong>, често със септичен характер.</li><li><strong>Общомозъчна симптоматика</strong> — силно главоболие, степенни нарушения в съзнанието, парциални и генерализирани епилептични пристъпи.</li><li><strong>Менингеални симптоми</strong>.</li><li><strong>Огнищна неврологична симптоматика</strong> — хемипареза, лезия на черепно-мозъчни нерви, афазия и други прояви според локализацията.</li></ol><p>В хроничния стадий, след формиране на капсула, клиничната картина е на <strong>пространство-заемащ процес</strong>. Наблюдава се синдром на интракраниална хипертенсия с главоболие, повръщане, двустранен папиледем и евентуално количествени нарушения в съзнанието.</p><h2>Диагноза</h2><p>Обичайно се установява периферна левкоцитоза с неутрофилия.</p><p>При ликворно изследване ликворът изтича под повишено налягане. Налице са <strong>плеоцитоза до 1–2 × 10⁹/l</strong>, <strong>хиперпротеинрахия 0,5–5,0 g/l</strong> и <strong>ксантохромия</strong>.</p><p><strong>Лумбалната пункция е противопоказана</strong> при повишено интракраниално налягане, защото създава условия за вклиняване и пробив на абсцеса към ликворните пространства.</p><p><strong>КТ</strong> показва окръглена хиподенсна зона, заобиколена от хиперденсен вал на абсцесната капсула.</p><h2>Лечение</h2><p>В началния стадий се започва консервативна терапия — комбинация от <strong>широкоспектърни антибиотици</strong>, които покриват грам-положителна и грам-отрицателна аеробна и анаеробна флора. Обикновено се използват <strong>цефалоспорини трета генерация</strong>.</p><p>Оперативно лечение се прилага при добре капсулирани, големи повърхностни абсцеси, при мултифокални абсцеси, посттравматични абсцеси, при наличие на голяма дислокация и при недобро повлияване от консервативната терапия.</p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 55. Енцефалити и енцефаломиелити. Класификация.</h1><p>Възпалителните заболявания на главния мозък представляват група нозологични единици с разнообразна етиология, обединени с наименованието <strong>енцефалити</strong>. Когато процесът обхваща гръбначния мозък, говорим за <strong>миелити</strong>, а при едновременно засягане на главния и гръбначния мозък – <strong>енцефаломиелити</strong>.</p><p>Често възпалителният процес не се ограничава само до мозъчната тъкан, а въвлича и съседни структури:</p><ul><li><strong>Менингоенцефалити</strong> – ангажиране на менингите.</li><li><strong>Менингоенцефаломиелополирадикулоневрити (невраксити)</strong> – обхващане и на периферните нерви.</li><li><strong>Церебелит</strong> – рядка форма, ограничена само в малкия мозък.</li></ul><h3>Класификация на енцефалитите</h3><p>Класифицирането се основава на няколко основни принципа, като <strong>етиологичният</strong> се счита за най-важен.</p><h4>Според типа увредено мозъчно вещество:</h4><ol><li><strong>Полиоенцефалити / Полиомиелити</strong> – засягат сивото вещество.</li><li><strong>Левкоенцефалити</strong> – засягат бялото вещество.</li><li><strong>Паненцефалити</strong> – едновременно засягане на бялото и сивото вещество.</li></ol><h4>Според етиологията (причинителя):</h4><p>Инфекциозните агенти могат да бъдат <strong>вируси, бактерии, гъбички или паразити</strong>. Най-чести са <strong>вирусните енцефалити</strong>, които се отличават с епидемичност, контагиозност, сезонност и специфично климатогеографско разпространение.</p><h4>Според начина на заразяване:</h4><ul><li><strong>Първични:</strong> Причинени от <strong>невротропни агенти</strong>, които директно атакуват мозъчната тъкан.</li><li><strong>Вторични:</strong> Развиват се, когато причинителят първоначално засяга други органи и системи и впоследствие обхваща мозъка.</li></ul><h4>Според хода на протичане:</h4><p>В зависимост от бързината на развитие, биват <strong>остри, подостри и хронични</strong>. Трябва да се прави разлика с термина <strong>енцефалопатия</strong>, който се използва, когато промените не са възпалителни, а първично дистрофични.</p><h3>Клинична картина (Енцефалитен синдром)</h3><p>Клиничната картина е съчетание от <strong>общоинфекциозен синдром</strong> и специфични неврологични нарушения, разделени в няколко подсиндрома:</p><ol><li><strong>Огнищен синдром:</strong> Проявява се с централни парези, парализи и сетивни нарушения.</li><li><strong>Хипертензионен синдром:</strong> Дължи се на мозъчен оток и повишено вътречерепно налягане. Включва <strong>силно главоболие, повръщане, брадикардия</strong> и нарушения на съзнанието.</li><li><strong>Менингорадикуларен синдром.</strong></li><li><strong>Ликворен синдром:</strong> Отразява възпалителните промени в ликвора.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Poliomyelitis anterior acuta (Полиомиелит, детски паралич, болест на Heine - Medin)</h2><p><strong>Полиомиелитът</strong> е остро инфекциозно заболяване, причинено от вирус със специфичен тропизъм към <strong>мотоневроните в предните рога</strong> на гръбначния мозък и двигателните ядра на краниалните нерви в мозъчния ствол. Клинично се характеризира с развитието на <strong>асиметрични вяли мускулни парези и парализи</strong>. \n\nВ региони с ефективна ваксинационна програма, подобен синдром на остър преден полиомиелит може да бъде причинен от други ентеровируси (<strong>Coxsackie групи А и B</strong>, <strong>ECHO-вируси</strong>), като при тях протичането обикновено е по-доброкачествено.</p><h3>Патоморфология</h3><p>Процесът засяга предимно <strong>сивото вещество</strong> на предните и странични рога на гръбначния мозък (особено в шийната и поясната интумесценция). Засягат се и моторните ядра на черепно-мозъчните нерви: <strong>n. facialis, n. vagus, n. glossopharyngeus, n. hypoglossus</strong> и ретикуларната формация.\n\nОсновни патологични промени:</p><ul><li><strong>Възпалителна левкоцитна инфилтрация</strong> (преминаваща в мононуклеарни периваскуларни струпвания).</li><li><strong>Централна до тежка хроматолиза</strong> на нервните клетки.</li><li><strong>Микроглиална инфилтрация и невронофагия</strong>.</li></ul><h3>Клинични прояви и стадии</h3><p>Инкубационният период варира между <strong>1 и 3 седмици</strong>. Заболяването може да протече безсимптомно, като лека инфекция, в менингитна форма или с пълно развитие на паралитичната картина.</p><h4>Стадии на развитие:</h4><ol><li><strong>Общоинфекциозен стадий:</strong> Висока температура (38 - 40°C), главоболие, болки в гърлото, мускулите и ставите. Наблюдават се адинамия, анорексия, гадене и повръщане. Продължава няколко дни.</li><li><strong>Препаралитичен стадий:</strong> Повторно повишаване на температурата, главоболие и изразен <strong>менингорадикуларен синдром</strong> (вратна ригидност, симптом на Брудзински). Характерни са обща възбудимост и хиперестезия.</li><li><strong>Паралитичен стадий:</strong> Остро развитие на <strong>периферни несиметрични парализи</strong>, ангажиращи предимно проксималните мускулни групи на долните крайници. Сухожилните рефлекси отслабват или изчезват. При засягане на ЧМН ядрата се развива <strong>булбарна парализа</strong>. Възможни са т.нар. <strong>\"сутрешни парализи\"</strong> при малки деца.</li><li><strong>Възстановителен стадий:</strong> Започва 10-15 дни след началото на парализите. Процесът е бавен и зависи от броя на оцелелите мотоневрони (продължава до 2-3 години).</li><li><strong>Резидуален стадий:</strong> Настъпва след третата година. Остатъчните парези са трайни, съпроводени от <strong>мускулна атрофия</strong> и трофични нарушения в костите и ставите.</li></ol><h3>Диагноза и Лечение</h3><p><strong>Диагнозата</strong> се верифицира чрез:</p><ul><li>Клинична картина (асиметрични парализи + менингеален синдром).</li><li>Епидемиологична обстановка.</li><li><strong>Вирусологично изследване</strong> на фекални проби или смив от носоглътката.</li></ul><p><strong>Медикаментозна терапия:</strong></p><ul><li><strong>Симптоматични средства:</strong> Антипиретици, витамини от група В и Е.</li><li><strong>Патогенетични средства:</strong> Кортикостероиди (противовъзпалително и противооточно действие), дехидратираща терапия.</li><li><strong>Специфични и възстановителни средства:</strong> Имунни антивирусни препарати, антихолинестеразни средства (<strong>Nivalin</strong>).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Бяс (Lyssa, Rabies)</h2><h3>Етиология и патогенеза</h3><p><strong>Бясът</strong> е тежък вирусен полиоенцефалит (антропозооноза), характеризиращ се с дълъг инкубационен период, специфична клинична картина и почти винаги летален изход.</p><ul><li><strong>Причинител:</strong> Rabies-вирус.</li><li><strong>Начин на заразяване:</strong> Трансдермално, чрез ухапване от болно животно (диво – лисици, вълци; или домашно – кучета, котки).</li><li><strong>Разпространение:</strong> Вирусът се придвижва по <strong>периферните нерви</strong> в посока към централната нервна система (ЦНС).</li></ul><h3>Патоморфология</h3><p>Процесът засяга най-вече <strong>булбарните сиви ядра</strong> и ядрата на средния мозък около третия вентрикул. Възпалителната реакция е най-силно изразена в мозъчния ствол с лимфоцитни инфилтрати и малки фокуси на възпалителна некроза.</p><p>Патогномоничен белег са <strong>телцата на Негри</strong> – специфични интрацелуларни цитоплазмени еозинофилни включвания в нервните клетки.</p><h3>Клинични прояви</h3><p>Инкубационният период обикновено е между <strong>20 и 60 дни</strong>, но може да бъде и по-кратък в зависимост от мястото на ухапване. Заболяването протича в три стадия:</p><h4>1. Продромален стадий (2-4 дни)</h4><p>Започва с повишена температура, главоболие и общо неразположение. Характерни са безсъние, емоционална нестабилност, както и <strong>изтръпване и болки в мястото на ухапване</strong>.</p><h4>2. Възбуден стадий</h4><p>Характеризира се с тежка <strong>психомоторна възбуда</strong>, страхова напрегнатост и безпокойство. Наблюдава се свръхвъзбудимост на булбарните нерви, водеща до спазми на ларингеалната, фарингеалната и дихателната мускулатура. Проявяват се:</p><ul><li><strong>Хидрофобия</strong> (страх от вода при опит за пиене).</li><li><strong>Аерофобия</strong> и <strong>фотофобия</strong>.</li></ul><h4>3. Паралитичен стадий</h4><p>Булбарната възбуда преминава в <strong>булбарна парализа</strong>. Наблюдават се:</p><ul><li>Дизартрия и дисфагия.</li><li><strong>Хиперсаливация</strong> (обилно слюноотделяне) и поява на \"пяна на устата\".</li></ul><p>Завършва с дихателна парализа, кома и <strong>смърт</strong> в рамките на 5-10 дни.</p><h3>Профилактика</h3><p>Профилактиката трябва да започне незабавно след експозиция:</p><ol><li><strong>Пасивна имунизация:</strong> Прилага се човешки <strong>противобесен имуноглобулин</strong> в доза <strong>20 Е/кг</strong>. Половината доза се инфилтрира около раната, а останалата част се инжектира интрамускулно.</li><li><strong>Активна имунизация:</strong> Следва пасивната имунизация след интервал от 10 - 20 дни.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Кърлежови паненцефалити</h2><h3>Етиология и основни форми</h3><p>Кърлежовите паненцефалити представляват група инфекциозни заболявания, пренасяни чрез кърлежи. Основните клинични варианти включват:</p><ul><li><strong>Пролетно-летен кърлежов паненцефалит</strong>.</li><li><strong>Средноевропейски вариант</strong>.</li><li><strong>Двувълнов менингоенцефалит</strong>.</li></ul><h3>Патоморфология</h3><p>Заболяването засяга <strong>сивото вещество</strong> на главния мозък. Патологоанатомично се установява <strong>дифузен възпалително-дегенеративен процес</strong>, който включва:</p><ul><li><strong>Периваскуларни инфилтрати</strong> и деструктивен васкулит.</li><li><strong>Невронофагия</strong> и образуване на некротични огнища.</li><li>Наличие на <strong>микрохеморагии</strong> (малки кръвоизливи).</li></ul><h3>Клинична картина</h3><p>Най-характерна за тези форми е <strong>полиоенцефаломиелитната симптоматика</strong>. Клиничните прояви включват:</p><ul><li><strong>Вяла парализа на шийната мускулатура:</strong> Специфичен симптом, водещ до типичното <strong>увисване на главата</strong>.</li><li><strong>Общомозъчни симптоми:</strong> Нарушение на съзнанието и възможни епилептични пристъпи.</li><li><strong>Менингеален синдром:</strong> Придружен от промени в ликвора – предимно <strong>лимфоцитарна плеоцитоза</strong>.</li></ul><h3>Диагноза и особености</h3><p>Диагностичният процес се опира на комбинацията от неврологичните симптоми (парализи на шията) и анамнестични данни за ухапване от кърлеж в съответния сезон. Ликворното изследване верифицира възпалителния характер на процеса.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 56. Остри вторични вирусни енцефалити: постинфекциозни и постваксинални.</h1><h2>Етиология и патогенеза</h2><p>Постинфекциозните и постваксиналните вторични вирусни енцефаломиелити са рядко, но сериозно усложнение на остри вирусни инфекции или имунизации.</p><p><strong>Основни причинители:</strong></p><ul><li><strong>Инфекции:</strong> Морбили, варицела, рубеола, паротит, грип и др.</li><li><strong>Ваксинации:</strong> Предимно след ваксинация срещу вариола и бяс.</li></ul><p><strong>Патогенеза:</strong></p><p>За разлика от първичните енцефалити, тук липсва директна вирусна инвазия в ЦНС. Заболяванията имат <strong>обща автоимунна патогенеза</strong> – имунномедиирано възпаление, което се отключва от предхождащата инфекция.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патоморфология</h2><p>Промените са характерни за <strong>перивенозен демиелинизиращ левкоенцефалит</strong>. Основните характеристики включват:</p><ul><li><strong>Демиелинизация:</strong> Многобройни огнища с различна големина, разположени около малките и средни вени в главния и гръбначния мозък.</li><li><strong>Перивенозна възпалителна реакция.</strong></li><li><strong>Хеморагии:</strong> При тежки токсични прояви (особено при морбили и грип) се наблюдават и перивенозни кръвоизливи.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Клинични прояви</h2><p>Симптомите обикновено се развиват <strong>след най-острата фаза</strong> на основната инфекция. В зависимост от локализацията на процеса се наблюдават следните форми:</p><h3>1. Енцефалитна форма</h3><ul><li>Остро начало с висок фебрилитет и главоболие.</li><li>Нарушения на съзнанието: дезориентираност, сомнолентност, а в тежки случаи – <strong>кома</strong>.</li><li><strong>Епилептични пристъпи</strong> (парциални или генерализирани).</li><li>Огнищна неврологична симптоматика: пирамидна и екстрапирамидна прояви.</li></ul><h3>2. Миелитна форма</h3><ul><li>Паретични прояви: от параплегия до <strong>квадриплегия</strong>.</li><li>Сетивни нарушения от <strong>проводников тип</strong>.</li><li>Тазово-резервоарни нарушения (смущения в уринирането и дефекацията).</li></ul><h3>3. Церебеларна форма</h3><ul><li>При ангажиране на малкия мозък преобладават симптомите на <strong>церебеларна атаксия</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение и профилактика</h2><p><strong>Лечение:</strong></p><ul><li><strong>Кортикостероиди:</strong> Основно средство за овладяване на имунния отговор.</li><li><strong>Плазмафереза и интравенозен имуноглобулин:</strong> Прилагат се при фулминантни (светкавични) случаи с благоприятен ефект.</li></ul><p><strong>Профилактика:</strong></p><p>Честотата на тези усложнения е значително намалена през последните десетилетия благодарение на:</p><ol><li>Широкото използване на <strong>имунизация срещу морбили</strong>.</li><li>Прекратяване на ваксинацията срещу вариола.</li><li>Използване на ваксини против бяс, които <strong>не съдържат нервна тъкан</strong>.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 57. Хиперкинетичен прогресиращ (Субакутен склерозиращ) паненцефалит (ССПЕ)</h1><h2>Етиология</h2><p><strong>ССПЕ</strong> е резултат от <strong>бавновирусна персистираща морбилозна инфекция</strong>. Заболяването се развива години след боледуване от морбили в много ранна детска възраст.</p><ul><li><strong>Механизъм:</strong> Вирусът персистира дългогодишно в организма, претърпява генетични промени и формира т.нар. <strong>\"дефектни форми\"</strong>. </li><li><strong>Имунен отговор:</strong> Тези дефектни форми не могат да бъдат ефективно атакувани от имунната система. Заедно с непроменените вируси те образуват <strong>имунни комплекси</strong>, които провокират дифузен възпалителен процес (енцефалит).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патоморфология</h2><p>Заболяването има характер на <strong>паненцефалит</strong> (засяга и сивото, и бялото вещество) с дифузно разпространение:</p><ul><li><strong>Сиво вещество:</strong> Обхваща мозъчната кора (особено челния и тилния дял), таламуса, хипоталамуса и ядрата в основата на понса. Наблюдава се деструкция на нервни клетки.</li><li><strong>Бяло вещество:</strong> Дегенерация на нервните влакна.</li><li><strong>Инфилтрация:</strong> Наличие на лимфоцити и мононуклеарни клетки в засегнатите зони.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Клинични прояви</h2><p>Типичният сценарий включва прекарани морбили в ранно детство, последвани от <strong>6-7 години асимптоматичен период</strong>. Заболяването започва субакутно и прогресира бавно (от 2 месеца до няколко години).</p><h3>Основни синдроми:</h3><ol><li><strong>Деменция:</strong> Често е начален симптом. Започва с уморяемост, променливо настроение и понижен успех в училище, прогресирайки до дълбока личностова деградация.</li><li><strong>Хиперкинези (Водещ симптом):</strong> Неволеви движения, често миоклонични или балистични. Описват се като:</li><ul><li>Резки движения като \"удар от електрически ток\".</li><li><strong>\"Внезапни поклони\"</strong> на тялото напред.</li><li>Широко отваряне на устата (<strong>\"като риба на сухо\"</strong>).</li><li>Издаване на звуци, приличащи на <strong>\"крясък на чайка\"</strong>.</li></ul><li><strong>Тонусови промени:</strong> Първоначална хипотония, която постепенно преминава в <strong>прогресираща ригидна хипертония</strong>.</li><li><strong>Епилептични пристъпи:</strong> Парциални или генерализирани тонично-клонични припадъци.</li><li><strong>Хипоталамичен синдром:</strong> Вегетативни кризи (хиперхидроза, саливация), булимия/анорексия, екстремна хипертермия (до 42°С) и кахексия.</li><li><strong>Други (редки):</strong> Корова слепота, дизартрия, пирамидни и тазово-резервоарни нарушения.</li></ol><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Изследвания и ЕЕГ</h2><p>Най-специфичното изследване е <strong>Електроенцефалографията (ЕЕГ)</strong>. Тя показва:</p><ul><li>Множество бавни делта- и тета-вълни.</li><li><strong>Радермекерови комплекси:</strong> Типични периодични генерализирани разряди от остри вълни, последвани от поредица бавни вълни.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Лечение и прогноза</h2><ul><li><strong>Лечение:</strong> Към момента е <strong>безрезултатно</strong>. Правени са опити с <em>Amantadin</em>, <em>Alfa-interferon</em> и други препарати, но без съществен успех.</li><li><strong>Прогноза:</strong> Изключително <strong>лоша</strong>. Заболяването е с прогресиращ ход и неизбежен <strong>фатален изход</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 58. Енцефалити при персистиращи и рекурентни херпесни вирусни инфекции. Херпес симплекс и херпес зостер менингоенцефалити.</h1><h2>Herpes simplex вирусен енцефалит (HSV-1)</h2><p><strong>Етиологията</strong> определя HSV енцефалита като най-честия спорадичен остър вирусен енцефалит. Може да засегне лица във всяка възраст.</p><ul><li><strong>Причинители:</strong> Почти винаги <strong>HSV тип 1</strong> (свързан с орални лезии). <strong>HSV тип 2</strong> се среща предимно в неонатална възраст при заразяване от майката.</li></ul><h3>Патоморфология</h3><p>Характерни са изразени <strong>хеморагично-некротични лезии</strong>, локализирани в:</p><ul><li><strong>Темпоробазалните</strong> и <strong>фронто-орбиталните</strong> отдели на мозъка.</li><li>Силно се уврежда <strong>лимбичната система</strong>.</li></ul><p>Тази специфична локализация е патогномонична и насочва към диагнозата още при огледа на макроскопските препарати.</p><h3>Клинични прояви</h3><p>Началото е <strong>остро</strong> (в рамките на няколко дни) със следната динамика:</p><ol><li><strong>Общи симптоми:</strong> Хиперпирексия, силно главоболие и дезориентация.</li><li><strong>Специфични прояви:</strong> Обонятелни и вкусови халюцинации, аносмия (загуба на обоняние).</li><li><strong>Психични промени:</strong> Кратък период на промяна на личността, делир или психотично поведение.</li><li><strong>Неврологичен дефицит:</strong> Афатични нарушения, епилептични пристъпи, пирамидна симптоматика.</li><li><strong>Терминална фаза:</strong> Масивен мозъчен оток и <strong>темпорално вклиняване</strong>, водещи до кома и респираторен арест.</li></ol><h3>Изследвания и Лечение</h3><ul><li><strong>Ликвор:</strong> Повишено налягане, плеоцитоза (10–500.10⁶/l), лимфоцити, понякога еритроцити (\"кървав\" ликвор при некроза).</li><li><strong>Диагностика:</strong> <strong>PCR</strong> за ДНК в ликвора (най-чувствителен метод) и МРТ (визуализира кортикални нарушения).</li><li><strong>Лечение:</strong> Спешно венозно приложение на <strong>Acyclovir (30 mg/kg дневно)</strong> за 10–14 дни. Прилагат се и противооточни средства.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Herpes zoster вирусен енцефалит</h2><h3>Патогенеза и патоморфология</h3><p>Вирусът на варицелата (<strong>Varicella-zoster</strong>) персистира в латентно състояние в <strong>невроните на сетивните ганглии</strong>. При имунен дефицит той се реактивира.</p><ul><li><strong>Локализация:</strong> Възпаление до некроза в краниалните и спиналните сетивни ганглии.</li></ul><h3>Клинична картина</h3><p>Най-често се изявява като <strong>ганглиорадикулит</strong> или <strong>ганглионеврит</strong>:</p><ul><li>Радикулерна болка и типични <strong>кожни везикулни ерупции</strong>.</li><li>Сегментни сетивни и двигателни нарушения.</li></ul><p><strong>Усложнения:</strong></p><ol><li><strong>Миелит:</strong> Рядко усложнение на торакалния зостер; изразява се с асиметрична парапареза и тазово-резервоарни нарушения.</li><li><strong>Зостеров енцефалит:</strong> Среща се предимно при <strong>имуносупресирани болни</strong>. Проявява се с дезориентираност, сънливост, нисък фебрилитет и лек менингеален синдром. Прогнозата за възстановяване при леките форми е добра.</li></ol><h3>Диагноза и Лечение</h3><ul><li><strong>Диагноза:</strong> Директна имунофлуоресценция или намиране на <strong>мултинуклеарни гигантски клетки</strong> в натривка от кожна лезия.</li><li><strong>Лечение:</strong> Интравенозен <strong>Acyclovir</strong> при поява на усложнения.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 59. Трансмисивни спонгиформени енцефалопатии (Прионови болести)</h1><h2>Обща характеристика на прионите</h2><p><strong>Прионът</strong> е уникален инфекциозен агент, изграден единствено от <strong>протеин</strong>, без наличие на нуклеинова киселина. </p><ul><li><strong>Конфигурации на прионовия протеин (PrP):</strong></li><ul><li><strong>PrPn (нормална):</strong> Открива се по повърхността на невроните в здравия организъм.</li><li><strong>PrPs (патологична - \"scrapie\"):</strong> Резултат от специфични генетични мутации. Тя е изключително стабилна и резистентна на външни влияния.</li></ul><li><strong>Механизъм:</strong> Мутиралата форма (PrPs) трансформира нормалните протеини в патологични, които се натрупват и увреждат мозъчната тъкан. Имунната система не реагира, тъй като ги разпознава като естествени протеини.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Патоморфология</h2><p>Характерни са специфични невъзпалителни промени, известни като <strong>status spongiosus</strong> (гъбест вид):</p><ul><li>Вакуолизация на цитоплазмата на невроните.</li><li>Невронална загуба.</li><li>Астроглиоза (пролиферация на глиални клетки).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Субакутна спонгиформена енцефалопатия (Болест на Creutzfeldt - Jakob)</h2><p>Това е най-честата прионова болест при хората. Абнормният протеин се кодира от гена <strong>PRNP</strong> на 20-а хромозома.</p><h3>Етиологични форми:</h3><ol><li><strong>Спорадична (85%):</strong> Спонтанна мутация.</li><li><strong>Фамилна (10%):</strong> Наследствена трансмисия.</li><li><strong>Ятрогенна:</strong> Чрез корнеална трансплантация или присаждане на dura mater.</li><li><strong>Нов вариант (vCJD):</strong> Пренасяне от говеда на хора (чрез консумация на заразен мозък).</li></ol><h3>Клинични прояви:</h3><p>Заболяването засяга предимно късната средна възраст. Характеризира се с бърза прогресия:</p><ul><li><strong>Продромални симптоми:</strong> Умора, загуба на тегло, депресия, нарушения на съня.</li><li><strong>Неврологична картина:</strong> * Бързо прогресираща <strong>деменция</strong>.</li><ul><li><strong>Миоклонии</strong> (в почти 100% от случаите).</li><li>Церебеларна атаксия, афазия, зрителни халюцинации и корова слепота.</li><li>Ригидно повишен мускулен тонус и крайни стадии с <strong>акинетичен мутизъм</strong>.</li></ul><li><strong>Ход:</strong> Обикновено фатален край в рамките на 6 месеца (рядко до 2 години).</li></ul><h3>Изследвания:</h3><ul><li><strong>ЕЕГ:</strong> Специфични периодични комплекси.</li><li><strong>Ликвор:</strong> Наличие на специфични протеинови маркери (белтък 14-3-3).</li><li><strong>КТ/МРТ:</strong> Корова атрофия в напреднали стадии.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Синдром на Gerstmann - Straussler - Scheinker</h2><p>Рядко <strong>автозомно-доминантно</strong> наследствено заболяване (мутация на PrP гена). </p><ul><li><strong>Клинична картина:</strong> Започва в средна възраст. Протича по-хронично (2–6 години). </li><li><strong>Водещи симптоми:</strong> Прогресивна церебеларна атаксия, дизартрия, нистагъм и сравнително лека деменция. </li><li><strong>Морфология:</strong> Множество <strong>амилоидни плаки</strong> в мозъчната тъкан.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Kuru (Куру)</h2><p>Разпространена в миналото сред племето Форе в Нова Гвинея поради ритуален канибализъм.</p><ul><li><strong>Инкубационен период:</strong> Изключително дълъг (от 5 до 30 години).</li><li><strong>Клинични прояви:</strong> Наричана \"малкомозъчна спонгиформена енцефалопатия\". Преобладава <strong>тежка атаксия при ходене</strong>, интенционен тремор, прогресираща слабост до пълна имобилизация и смърт за 3 до 12 месеца. </li><li><strong>Патоморфология:</strong> Характерни \"Куру плаки\" (амилоидни плаки) в церебеларната кора.</li></ul><p><strong>Прогноза и лечение:</strong> За всички прионови болести <strong>няма етиологично лечение</strong>. Прогнозата е абсолютно неблагоприятна с фатален изход.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Невроборелиоза и Невролуес</h1><h2>Лаймска болест (Невроборелиоза)</h2><p><strong>Етиология:</strong> Причинява се от спирохетата <strong>Borrelia burgdorferi</strong>.</p><p><strong>Епидемиология:</strong> Антропозооноза с резервоар гризачи и диви/домашни животни. Преносители са кърлежи от рода <strong>Ixodes</strong>.</p><h3>Патогенеза и патоанатомия</h3><ul><li><strong>Механизъм:</strong> Директна тъканна инвазия и индиректни имунопатологични механизми (демиелинизация в ЦНС и ПНС).</li><li><strong>Локализация:</strong> Дистрофични промени и наличие на причинителя в кожа, лимфни възли, менинги, миокард, синовиална течност и др.</li></ul><h3>Клинична картина (Три стадия)</h3><ol><li><strong>Първи стадий (3–30 дни след ухапване):</strong>&nbsp;</li><ul><li>Характерен <strong>Erythema chronicum migrans</strong> – еритем на мястото на ухапването, който нараства периферно и избледнява централно (пръстеновидна лезия).</li><li>Лек общоинфекциозен синдром: фебрилитет, миалгии, лимфаденопатия.</li></ul><li><strong>Втори стадий (седмици до месеци по-късно):</strong> * Засягане на сърцето (миокардит с ритъмни нарушения). </li><ul><li><strong>Класическа неврологична триада:</strong> Серозен менингит, краниална невропатия и радикулоневропатия.</li></ul><li><strong>Трети стадий (месеци до години по-късно):</strong> * Хроничен прогресивен енцефаломиелит, фокален енцефалит и лека дифузна енцефалопатия.</li><ul><li>Ставна патология и психиатрични синдроми.</li></ul></ol><h3>Лечение</h3><ul><li><strong>I стадий:</strong> Перорален <strong>Amoxicillin</strong> (500–1000 mg на всеки 6 часа) за 2–4 седмици.</li><li><strong>II и III стадий:</strong> Цефалоспорини III поколение (интравенозно).</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Невролуес (Невросифилис)</h2><p><strong>Етиология:</strong> Причинява се от <strong>Treponema pallidum</strong>. Заразяването е по полов път или чрез кръв. ЦНС може да бъде засегната във всеки стадий на инфекцията.</p><h3>Клинични форми на невросифилиса</h3><table><tbody><tr><td><strong><span style=\"color: rgb(88, 129, 87)\">Форма</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Начало</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Патоанатомия</span></strong></td><td><strong><span style=\"color: rgb(88, 129, 87)\">Клинична картина</span></strong></td></tr><tr><td><strong>Ранен (Асимптоматичен)</strong></td><td>До 1 год.</td><td>Ексудативни промени по менингите</td><td>Ликворен синдром без тежка клиника</td></tr><tr><td><strong>Остър сифилитичен менингит</strong></td><td>До 1 год.</td><td>Хидроцефалия</td><td>Изразен менингеален синдром</td></tr><tr><td><strong>Менинговаскуларен луес</strong></td><td>4–10 год.</td><td>Ендартериит, мозъчни инфаркти, менингомиелит</td><td>Исхемични инсулти, Паркинсонов синдром, парези</td></tr><tr><td><strong>Сифилитична гума</strong></td><td>Късен стадий</td><td>Хроничен гранулом с некроза</td><td>Симптоми на заемащ пространство процес (тумор-подобно)</td></tr><tr><td><strong>Tabes dorsalis</strong></td><td>15–20 год.</td><td>Алтерация на задни коренчета и задна стълбцова система</td><td><strong>Сензорна атаксия</strong>, болкови кризи, зенични разстройства, тазово-резервоарни нарушения</td></tr><tr><td><strong>Paralysis progressiva</strong></td><td>15–20 год.</td><td>Корова атрофия, хроничен менингоенцефалит</td><td>Тежка <strong>деменция</strong> и психична симптоматика</td></tr></tbody></table><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>Забележка:</strong> При Tabes dorsalis се засягат специфично задните ганглии и фуникули на гръбначния мозък, което води до загуба на дълбока сетивност.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 69. Епилепсия</h1><p>Епилепсиите са <strong>хронични заболявания </strong>на главния мозък с различна етиология. Характеризират се с <strong>повтарящи се пристъпи</strong>, възникващи на базата на <strong><u>свръхвъзбуда на определена популация неврони</u></strong>. Проявяват се с преходни клинични (двигателни, сетивни, автономни, психични и поведенчески) и електрофизиологични прояви. </p><ul><li><em>Важно:</em> Единични пристъпи или такива при остра увреда (без повторяемост) не се приемат за епилепсия.</li></ul><h3><strong>Етиология</strong></h3><p><strong>Мултифакторно </strong>заболяване, развиващо се при взаимодействието на:</p><ul><li>Генетични фактори.</li><li>Придобити фактори (директна или индиректна мозъчна увреда).</li></ul><h3><strong>Патогенеза&nbsp;</strong></h3><p>Изграждане на <strong><u>епилептично огнище</u></strong> от увредени, но неразрушени неврони. Характеризира се с:</p><ul><li><strong>Автономна възбудимост</strong>, дължаща се на&nbsp;частична пролонгирана деполяризация на клетъчните мембрани.</li><li>Повишена чувствителност към някои общи влияния.</li><li><strong>Локализация:</strong>&nbsp;</li><ul><li>При <strong>парциалните </strong>форми – в <u>мозъчната кора</u> или мрежови структури (<u>амигдала</u>, <u>хипокамп</u>).</li><li>При <strong>генерализираните </strong>форми – в <u>осцилиращия кортико-таламо-кортикален кръг</u>.</li></ul></ul><h3>Класификация на пристъпите</h3><h4><strong>1. Парциални (огнищни) пристъпи</strong></h4><ul><li><strong>Прости:</strong> Без загуба на съзнание; огнищно разположение в първичните кортикални полета. Прояви: гърчове, парестезии, сетивни халюцинации (звукови, зрителни, обонятелни, вкусови), психични прояви.</li><li><strong>Комплексни:</strong> С нарушение на съзнанието и сложна симптоматика. Често последвани от временна пространствена дезориентация.</li></ul><h4>2. Първично генерализирани пристъпи</h4><p>Внезапно и едновременно ангажиране на кората на двете хемисфери, изразяващо се с двустранно синхронни и симетрични клинични и ЕЕГ прояви.</p><ul><li><strong>Тонично-клонични пристъпи:</strong> Внезапна загуба на съзнание.</li><ol><li><em>Генерализирана тонична реакция:</em> Тоничен гърч, прехапване на езика, изпразване на тазови резервоари.</li><li><em>Генерализирана клонична реакция:</em> Клонични гърчове и отпускане на мускулатурата.</li><li><em>Постгърчова фаза:</em> Възстановяване на дишането и съзнанието. </li></ol><ul><li><em>Съпътстващи Белези:</em> Падане, напикаване, наранявания, широки нереагиращи зеници, амнезия, бавно възстановяване на съзнанието.</li></ul><li><strong>Генерализирани миоклонични пристъпи:</strong> Внезапни, кратки и бързи масивни мускулни контракции на крайниците и тялото (със или без нарушение на съзнанието).</li><li><strong>Генерализирани атонични пристъпи:</strong> Внезапна загуба на мускулен тонус, водеща до падане и нараняване на колената, лицето и др.</li><li><strong>Абсанси (генерелизирани неконвулсивни кризи):</strong> Кратко (5-30 сек.) нарушение на съзнанието с внезапно начало и край; фиксиране на погледа, спиране на текущата дейност и последващо нейно възстановяване; липса на спомен.</li></ul><h3>Диагноза</h3><ol><li><strong>Анамнеза:</strong> Съществена роля на болния и близките му.</li><li><strong>ЕЕГ (Стандартна):</strong> Основно изследване, което се извършва се по време на пристъп и извън него. Почти винаги се регистрират характерни електрически прояви по време на пристъп.</li><li><strong>Допълнителни методи:</strong> Холтер-ЕЕГ, ЕЕГ-телеметрия, нощна полисомнография, Видео-ЕЕГ (увеличават диагностиката до 80%).</li><li><strong>Образна диагностика:</strong> КТ и МРТ за доказване на лезионни епилепсии.</li></ol><h3><strong>Лечение</strong></h3><ul><li>Започва се винаги с <strong>МОНОТЕРАПИЯ</strong>.</li><li>При неуспех се преминава към <strong>ПОЛИТЕРАПИЯ</strong>.</li></ul><br><br><br><br>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
